  ('dietitian-moex-01006', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於合成三酸甘油酯（triglyceride）過程的敘述，何者錯誤？', '["磷脂酸（phosphatidicacid）是三酸甘油酯合成時必要的中間產物", "三酸甘油酯合成時的甘油骨架僅來自於胺基酸脫胺後的代謝產物", "脂肪酸需以脂肪醯基-輔酶A（fattyacyl-CoA）型式參與合成", "雙酸甘油酯是合成三酸甘油酯的前身"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01007', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在電子傳遞鏈的複合物中，何者不直接與泛醌（ubiquinone）聯結？', '["complexI（reductase）", "complexII（reductase）", "complexIII（reductase）", "complexIV（oxidase）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01008', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關糖解作用及糖質新生作用的敘述，何者正確？', '["果糖無法作為肝臟中糖質新生作用之先質，因其無法經由磷酸化反應生成 fructose-6-phosphate", "紅血球只能藉由無氧糖解作用來分解葡萄糖，作為其能量的主要來源", "在骨骼肌中，糖質新生作用為糖解作用的逆反應", "亞麻油酸可以分解為 acetyl-CoA，故可以做為糖質新生作用的先質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01009', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於脂解酶（lipase）生化代謝之敘述，何者錯誤？', '["胃的gastriclipase，可切解部分三酸甘油酯sn3位置，生成雙酸甘油酯", "小腸中胰脂解酶（pancreaticlipase），可切解三酸甘油酯的sn1或sn3位置，生成雙酸甘油酯", "輔脂解酶（colipase），是將雙酸甘油酯切解成單酸甘油酯與脂肪酸", "磷脂解酶（phospholipase）A2，可將卵磷脂（lecithin）切解為脫脂卵磷脂（lysolecithin）與脂肪酸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
